const MIN_PACE=2.83;const MAX_PACE=8;const MIN_SPEED=7.5;const MAX_SPEED=21.2;let isDragging=false;document.addEventListener("DOMContentLoaded",function(){initCalculadora();setupEventListeners()});function initCalculadora(){const initialPace=5;const initialSpeed=60/initialPace;updateDisplays(initialPace,initialSpeed);updateSliderPosition(initialPace)}function setupEventListeners(){const sliderHandle=document.getElementById("slider-handle");const sliderTrack=document.querySelector(".slider-track");const paceEdit=document.getElementById("pace-edit");const speedEdit=document.getElementById("speed-edit");sliderHandle.addEventListener("mousedown",startDrag);sliderTrack.addEventListener("click",handleTrackClick);paceEdit.addEventListener("input",handlePaceInput);paceEdit.addEventListener("blur",handlePaceBlur);speedEdit.addEventListener("input",handleSpeedInput);speedEdit.addEventListener("blur",handleSpeedBlur);document.addEventListener("mousemove",drag);document.addEventListener("mouseup",stopDrag);sliderHandle.addEventListener("touchstart",startDragTouch);document.addEventListener("touchmove",dragTouch);document.addEventListener("touchend",stopDrag)}function startDrag(e){isDragging=true;e.preventDefault()}function startDragTouch(e){isDragging=true;e.preventDefault()}function drag(e){if(!isDragging)return;const sliderTrack=document.querySelector(".slider-track");const rect=sliderTrack.getBoundingClientRect();const x=Math.max(0,Math.min(e.clientX-rect.left,rect.width));const percentage=x/rect.width;updateFromSlider(percentage)}function dragTouch(e){if(!isDragging)return;const touch=e.touches[0];const sliderTrack=document.querySelector(".slider-track");const rect=sliderTrack.getBoundingClientRect();const x=Math.max(0,Math.min(touch.clientX-rect.left,rect.width));const percentage=x/rect.width;updateFromSlider(percentage)}function stopDrag(){isDragging=false}function handleTrackClick(e){if(isDragging)return;const rect=e.currentTarget.getBoundingClientRect();const x=e.clientX-rect.left;const percentage=x/rect.width;updateFromSlider(percentage)}function updateFromSlider(percentage){const pace=MAX_PACE-percentage*(MAX_PACE-MIN_PACE);const speed=60/pace;updateDisplays(pace,speed);updateSliderPosition(pace)}function updateDisplays(pace,speed){const paceInput=document.getElementById("pace-input");const speedInput=document.getElementById("speed-input");const paceFormatted=formatPace(pace);const speedFormatted=speed.toFixed(1);paceInput.value=paceFormatted;speedInput.value=`${speedFormatted} km/h`}function updateSliderPosition(pace){const sliderHandle=document.getElementById("slider-handle");const sliderTrack=document.querySelector(".slider-track");const percentage=(MAX_PACE-pace)/(MAX_PACE-MIN_PACE);const trackWidth=sliderTrack.offsetWidth;const handleWidth=sliderHandle.offsetWidth;const position=percentage*(trackWidth-handleWidth);sliderHandle.style.left=`${position}px`}function formatPace(paceMinutes){const minutes=Math.floor(paceMinutes);const seconds=Math.round((paceMinutes-minutes)*60);return`${minutes}:${seconds.toString().padStart(2,"0")}/km`}function parsePace(paceString){paceString=paceString.replace("/km","").trim();const match=paceString.match(/^(\d+):(\d+)$/);if(match){const minutes=parseInt(match[1]);const seconds=parseInt(match[2]);return minutes+seconds/60}const decimal=parseFloat(paceString);if(!isNaN(decimal)){return decimal}return null}function handlePaceInput(e){const value=e.target.value;const pace=parsePace(value);if(pace&&pace>=MIN_PACE&&pace<=MAX_PACE){const speed=60/pace;updateDisplays(pace,speed);updateSliderPosition(pace);document.getElementById("speed-edit").value=speed.toFixed(1)}}function handlePaceBlur(e){const value=e.target.value;const pace=parsePace(value);if(!pace||pace<MIN_PACE||pace>MAX_PACE){const currentPace=getCurrentPaceFromDisplay();e.target.value=formatPace(currentPace).replace("/km","")}}function handleSpeedInput(e){const speed=parseFloat(e.target.value);if(speed&&speed>=MIN_SPEED&&speed<=MAX_SPEED){const pace=60/speed;updateDisplays(pace,speed);updateSliderPosition(pace);document.getElementById("pace-edit").value=formatPace(pace).replace("/km","")}}function handleSpeedBlur(e){const speed=parseFloat(e.target.value);if(!speed||speed<MIN_SPEED||speed>MAX_SPEED){const currentSpeed=getCurrentSpeedFromDisplay();e.target.value=currentSpeed.toFixed(1)}}function getCurrentPaceFromDisplay(){const paceInput=document.getElementById("pace-input");const paceString=paceInput.value;return parsePace(paceString)||5}function getCurrentSpeedFromDisplay(){const speedInput=document.getElementById("speed-input");const speedString=speedInput.value.replace(" km/h","");return parseFloat(speedString)||12}function validatePaceInput(input){input.value=input.value.replace(/[^0-9:.]/g,"");const parts=input.value.split(":");if(parts.length>2){input.value=parts[0]+":"+parts[1]}if(parts[1]&&parts[1].length>2){input.value=parts[0]+":"+parts[1].substring(0,2)}}document.addEventListener("DOMContentLoaded",function(){const paceEdit=document.getElementById("pace-edit");if(paceEdit){paceEdit.addEventListener("input",function(){validatePaceInput(this)})}});